import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Foire Aux Questions pour les joueurs","description":"Foire aux questions pour les joueurs et les administrateurs de serveur liés à Fabric.","frontmatter":{"title":"Foire Aux Questions pour les joueurs","description":"Foire aux questions pour les joueurs et les administrateurs de serveur liés à Fabric.","files":[]},"headers":[],"relativePath":"fr_fr/1.21.4/players/faq.md","filePath":"versions/1.21.4/translated/fr_fr/players/faq.md","lastUpdated":1760721669000}`);var a={name:`fr_fr/1.21.4/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Foire Aux Questions pour les joueurs <a class="header-anchor" href="#h1" aria-label="Permalink to “Foire Aux Questions pour les joueurs”">​</a></h1><p>Certaines questions sont posées très fréquemment, donc en voici une liste.</p><h2 id="quelles-versions-de-minecraft-sont-supportees-par-fabric-foire-aux-questions" tabindex="-1">Quelles versions de Minecraft sont supportées par Fabric ? Foire Aux Questions <a class="header-anchor" href="#quelles-versions-de-minecraft-sont-supportees-par-fabric-foire-aux-questions" aria-label="Permalink to “Quelles versions de Minecraft sont supportées par Fabric ? Foire Aux Questions”">​</a></h2><p>Officiellement, Fabric supporte toutes les versions de Minecraft, les snapshots <code>18w43b</code> et ultérieures et les releases <code>1.14</code> et ultérieures.</p><h2 id="where-can-i-download-published-fabric-mods" tabindex="-1">Où télécharger des mods Fabric ? <a class="header-anchor" href="#where-can-i-download-published-fabric-mods" aria-label="Permalink to “Où télécharger des mods Fabric ?”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Vous devriez toujours vérifier que vos mods proviennent d&#39;une source fiable. Consultez le guide <a href="./finding-mods">Trouver des mods</a> pour plus d&#39;informations.</p></div><p>La majorité des auteurs publient leurs mods sur <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> et <a href="https://www.curseforge.com/minecraft/search?class=mc-mods%5C&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>, cependant certains peuvent choisir de les mettre en ligne sur leurs sites personnels, ou sur d&#39;autres plateformes, telle qu&#39;un dépot/une repo GitHub.</p><h2 id="where-can-i-find-premade-fabric-modpacks" tabindex="-1">Où puis-je trouver des packs de mods préexistant pour Fabric ? <a class="header-anchor" href="#where-can-i-find-premade-fabric-modpacks" aria-label="Permalink to “Où puis-je trouver des packs de mods préexistant pour Fabric ?”">​</a></h2><p>Vous pouvez trouver des packs de mods conçu pour Fabric sur une variété de plateformes, telles que :</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks%5C&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};